import os
import json
import logging
import azure.functions as func
from azure.identity import DefaultAzureCredential
from azure.storage.blob import BlobClient
from azure.cosmos import CosmosClient, PartitionKey
from azure.eventgrid import EventGridPublisherClient, EventGridEvent
from azure.core.credentials import AzureKeyCredential
from azure.core.pipeline.transport import RequestsTransport
import requests

app = func.FunctionApp(http_auth_level=func.AuthLevel.FUNCTION)

logger = logging.getLogger("azure_function_mvp")
logger.setLevel(logging.INFO)

storage_account_url = os.environ.get("STORAGE_ACCOUNT_URL")
cosmos_endpoint = os.environ.get("COSMOS_ENDPOINT")
cosmos_database_name = os.environ.get("COSMOS_DATABASE_NAME", "mvpdb")
cosmos_container_name = os.environ.get("COSMOS_CONTAINER_NAME", "results")
eventgrid_topic_endpoint = os.environ.get("EVENTGRID_TOPIC_ENDPOINT")
eventgrid_topic_key = os.environ.get("EVENTGRID_TOPIC_KEY")
eventgrid_topic_hostname = os.environ.get("EVENTGRID_TOPIC_HOSTNAME")
eventgrid_event_type = os.environ.get("EVENTGRID_EVENT_TYPE", "MVP.FileProcessed")
eventgrid_subject_prefix = os.environ.get("EVENTGRID_SUBJECT_PREFIX", "files/processed")
cosmos_partition_key_path = os.environ.get("COSMOS_PARTITION_KEY_PATH", "/id")

credential = DefaultAzureCredential(exclude_interactive_browser_credential=True)

cosmos_client = None
cosmos_container = None
eventgrid_client = None

def get_cosmos_container():
    global cosmos_client, cosmos_container
    if cosmos_container is not None:
        return cosmos_container

    if not cosmos_endpoint:
        raise ValueError("COSMOS_ENDPOINT is required")

    cosmos_client = CosmosClient(url=cosmos_endpoint, credential=credential)
    db = cosmos_client.create_database_if_not_exists(id=cosmos_database_name)
    container = db.create_container_if_not_exists(
        id=cosmos_container_name,
        partition_key=PartitionKey(path=cosmos_partition_key_path),
        offer_throughput=400
    )
    cosmos_container = container
    return cosmos_container

def get_eventgrid_client():
    global eventgrid_client
    if eventgrid_client is not None:
        return eventgrid_client

    if eventgrid_topic_endpoint and eventgrid_topic_key:
        eventgrid_client = EventGridPublisherClient(
            endpoint=eventgrid_topic_endpoint,
            credential=AzureKeyCredential(eventgrid_topic_key),
            transport=RequestsTransport()
        )
        return eventgrid_client

    if eventgrid_topic_hostname:
        eventgrid_client = EventGridPublisherClient(
            endpoint=eventgrid_topic_hostname,
            credential=credential,
            transport=RequestsTransport()
        )
        return eventgrid_client

    raise ValueError("Either EVENTGRID_TOPIC_KEY + EVENTGRID_TOPIC_ENDPOINT or EVENTGRID_TOPIC_HOSTNAME must be set")

def process_blob(blob_url: str, blob_name: str):
    blob_client = BlobClient.from_blob_url(blob_url=blob_url, credential=credential)
    blob_data = blob_client.download_blob().readall()

    try:
        text = blob_data.decode("utf-8")
    except Exception:
        text = None

    result = {
        "id": blob_name.replace("/", "_"),
        "blob_name": blob_name,
        "blob_url": blob_url,
        "size_bytes": len(blob_data),
        "content_preview": text[:1000] if text else None,
        "status": "processed"
    }

    container = get_cosmos_container()
    container.upsert_item(result)

    event = EventGridEvent(
        subject=f"{eventgrid_subject_prefix}/{blob_name}",
        event_type=eventgrid_event_type,
        data={
            "blob_name": blob_name,
            "blob_url": blob_url,
            "status": "processed",
            "size_bytes": len(blob_data)
        },
        data_version="1.0"
    )

    client = get_eventgrid_client()
    client.send([event])

    return result

@app.function_name(name="BlobProcessor")
@app.blob_trigger(arg_name="blob", path="input/{name}", connection="AzureWebJobsStorage")
def blob_processor(blob: func.InputStream):
    logger.info("Processing blob: %s", blob.name)
    blob_url = f"{storage_account_url}/{blob.name}" if storage_account_url else blob.uri
    try:
        result = process_blob(blob_url=blob_url, blob_name=blob.name)
        logger.info("Processed blob successfully: %s", json.dumps(result))
    except Exception as e:
        logger.exception("Failed to process blob %s: %s", blob.name, str(e))
        raise

@app.function_name(name="Health")
@app.route(route="health", methods=["GET"])
def health(req: func.HttpRequest) -> func.HttpResponse:
    body = {
        "status": "ok",
        "cosmos_configured": bool(cosmos_endpoint),
        "eventgrid_configured": bool(eventgrid_topic_endpoint or eventgrid_topic_hostname),
        "storage_configured": bool(storage_account_url)
    }
    return func.HttpResponse(json.dumps(body), status_code=200, mimetype="application/json")

@app.function_name(name="ManualProcess")
@app.route(route="process", methods=["POST"])
def manual_process(req: func.HttpRequest) -> func.HttpResponse:
    try:
        payload = req.get_json()
    except Exception:
        return func.HttpResponse("Invalid JSON", status_code=400)

    blob_url = payload.get("blob_url")
    blob_name = payload.get("blob_name")

    if not blob_url or not blob_name:
        return func.HttpResponse("blob_url and blob_name are required", status_code=400)

    try:
        result = process_blob(blob_url=blob_url, blob_name=blob_name)
        return func.HttpResponse(json.dumps(result), status_code=200, mimetype="application/json")
    except Exception as e:
        logger.exception("Manual processing failed: %s", str(e))
        return func.HttpResponse(str(e), status_code=500)